UPDATE public.records SET form_data = '{"serial":"F/44-001","position":"Chief Executive Officer (CEO)","reports_to":"Board of Directors","responsibilities":"Management & Documentation (Clause 5, 6, 7.5) — PRIMARY OWNER\nSet overall strategic direction, vision, and business objectives\nApprove the Quality Manual (M/01) and Quality Policy\nEnsure Quality Policy and Objectives are compatible with strategic direction\nConduct Management Review Meetings at least every 6 months\nEnsure integration of QMS requirements into business processes\nPromote process approach and risk-based thinking\nEnsure resources needed for QMS are available\nApprove organizational structure and delegation of authority\nReview and approve major QMS changes and MOC Plans\nSales & Customer Service (Clause 8.2, 9.1.2) — PRIMARY OWNER (interim)\nOversee customer requirements identification and contract review\nMaintain strategic client relationships and key account management\nReview customer satisfaction data and ensure improvement\nEnsure statutory and regulatory requirements are met\nApprove proposals and service offerings to clients\nProcurement & Vendors (Clause 8.4) — PRIMARY OWNER (interim)\nAuthorize major purchase orders and subcontracting agreements\nReview and approve the Approved Supplier List\nEnsure externally provided processes conform to requirements\nOversee vendor evaluation and performance reviews\nOperations & Production (Clause 8.1, 8.5) — OVERSIGHT\nMonitor overall operational performance and service delivery\nReview project delivery timelines and resource utilization\nSupport scalability and operational growth initiatives\nEnsure adequate infrastructure for operations\nQuality & Audit (Clause 9, 10) — OVERSIGHT\nTake accountability for QMS effectiveness\nReview audit results, nonconformities, and corrective actions\nReview CAPA effectiveness and systemic improvements\nEnsure compliance with ISO 9001:2015\nHR & Training (Clause 7.2, 7.3) — OVERSIGHT\nEnsure organizational competence and talent management\nApprove headcount plans and key hiring decisions\nPromote culture of quality and continuous improvement\nSupport leadership development and succession planning\nR&D & Design (Clause 8.3) — OVERSIGHT\nEvaluate feasibility of new service types and market opportunities\nApprove R&D feasibility testing initiatives\nDrive innovation aligned with market trends\nFinancial & Risk Management — PRIMARY\nApprove budgets and ensure financial sustainability\nMonitor financial performance and profitability\nIdentify and manage strategic, operational, and financial risks\nQualifications & Requirements\nBachelor’s in Business Administration (Master’s preferred); 10+ years senior leadership; Strategic thinking, financial management, leadership\nKey Performance Indicators (KPIs)\nRevenue Growth: ≥20% annually\nCustomer Satisfaction: ≥90%\nEmployee Retention: ≥85%\nQMS Compliance: 100%\nStrategic Objectives: 100% achievement\nEmployee Name: Kareem Yehia\nEmployee Signature: _______________________\nDate: _______________________"}'::jsonb WHERE serial = 'F/44-001';
UPDATE public.records SET form_data = '{"serial":"F/44-002","position":"Operations Director","reports_to":"CEO (Kareem Yehia)","responsibilities":"Operations & Production (Clause 8.1, 8.5) — PRIMARY OWNER\nOversee all operational activities across all teams\nEnsure project timelines and delivery schedules are met\nMonitor resource allocation and capacity planning\nCoordinate between Operations Managers for workload distribution\nReview and approve operational workflows and work instructions\nEscalate resource constraints to CEO\nQuality & Audit (Clause 9, 10) — SECONDARY OWNER\nOversee quality assurance processes alongside QA Leader\nReview quality metrics from all operational teams\nEnsure corrective actions are implemented for operational nonconformities\nParticipate in internal audits\nReview service conformity data before client delivery\nEnsure nonconforming outputs are properly controlled\nManagement & Documentation (Clause 5, 6, 7.5) — PARTICIPANT\nParticipate in Management Review Meetings\nPresent operational performance data\nReport on process performance trends\nContribute to strategic planning\nSales & Customer Service (Clause 8.2, 9.1.2) — SUPPORT\nSupport contract review by assessing operational capacity\nEnsure teams understand customer requirements\nAddress customer complaints related to service delivery\nMonitor customer feedback and implement improvements\nHR & Training (Clause 7.2, 7.3) — SUPPORT\nIdentify training needs for operational teams\nEnsure team leaders are competent for their roles\nSupport performance appraisals for operations staff\nEnsure new employees receive operational induction\nR&D & Design (Clause 8.3) — PARTICIPANT\nEvaluate operational feasibility of new project types\nSupport testing of new workflows and methodologies\nProcurement & Vendors (Clause 8.4) — SUPPORT\nProvide requirements for tools and resources\nEvaluate vendor performance from operational perspective\nQualifications & Requirements\nBachelor’s in Business/Operations Management; 5+ years operations management in BPO; Leadership, project management, resource planning\nKey Performance Indicators (KPIs)\nOn-time Delivery: ≥95%\nOperational Efficiency: ≥90%\nTeam Utilization: ≥85%\nComplaint Resolution: <48h\nQuality Conformity: ≥95%\nEmployee Name: Eman El Serafy\nEmployee Signature: _______________________\nDate: _______________________"}'::jsonb WHERE serial = 'F/44-002';
UPDATE public.records SET form_data = '{"serial":"F/44-003","position":"Operations Manager / Quality Assurance Leader","reports_to":"Operations Director (Eman El Serafy)","responsibilities":"Operations & Production (Clause 8.1, 8.5) — PRIMARY OWNER\nManage daily operations for Get Vocal, Omniaz, Data Quality, Tennis, and General Tagging teams\nAssign projects and monitor team workloads\nEnsure project deliverables meet client specifications and deadlines\nCoordinate with Team Leaders (Mena Sami, Yara Khairy, Khaled Magdy) on task allocation\nMonitor production metrics and turnaround times\nImplement process improvements based on performance data\nQuality & Audit (Clause 9, 10) — PRIMARY OWNER\nLead quality assurance processes across all assigned teams\nDefine quality benchmarks and acceptance criteria per project type\nMonitor accuracy rates and quality metrics (data annotation accuracy, transcription quality)\nConduct quality checks at incoming, in-process, and final stages\nManage nonconformity identification and disposition\nInitiate Corrective Action Requests (CARs) for quality issues\nSupport internal audits as lead auditor or auditee\nReport quality performance to Operations Director and QMS Team Leader\nHR & Training (Clause 7.2, 7.3) — SUPPORT\nIdentify skill gaps in assigned teams\nConduct on-the-job training and mentoring\nEvaluate team member competence for project assignments\nParticipate in performance appraisals\nManagement & Documentation (Clause 5, 6, 7.5) — PARTICIPANT\nMaintain operational documentation and work instructions\nReport KPIs to QMS Team Leader\nParticipate in Management Review Meetings\nSales & Customer Service (Clause 8.2, 9.1.2) — SUPPORT\nReview client requirements for feasibility\nHandle quality-related customer complaints\nProvide input on service capability during contract review\nQualifications & Requirements\nBachelor’s degree; 3+ years in operations/quality in BPO; Strong analytical skills; Knowledge of data annotation processes; Quality management experience\nKey Performance Indicators (KPIs)\nQuality Accuracy Rate: ≥95%\nProject On-time Delivery: ≥95%\nTeam Productivity: ≥90%\nCAR Closure Rate: Within 30 days\nCustomer Satisfaction: ≥85%\nEmployee Name: Andrew Maged\nEmployee Signature: _______________________\nDate: _______________________"}'::jsonb WHERE serial = 'F/44-003';
UPDATE public.records SET form_data = '{"serial":"F/44-004","position":"Operations Manager — Video Production","reports_to":"Operations Director (Eman El Serafy)","responsibilities":"Operations & Production (Clause 8.1, 8.5) — PRIMARY OWNER\nManage all Video Teams (Nada Ahmed, Aya Said, Merolla George, Rahma El Sayed, Nada Mohey, Omnia Ramadan, Shymaa Sayed, Eman Hamada)\nOversee Video Training program (Yara Ehab, Training Specialist)\nAssign video projects and monitor team workloads\nEnsure video detection and analysis deliverables meet client specifications\nMonitor production volume and turnaround times for video projects\nManage General Tagging Projects assigned to video teams\nQuality & Audit (Clause 9, 10) — SUPPORT\nImplement quality checks for video detection accuracy\nMonitor false positive/negative rates in video analysis\nReport quality issues and initiate corrections\nSupport internal audits for video operations\nHR & Training (Clause 7.2, 7.3) — SUPPORT\nCoordinate with Yara Ehab on video team training programs\nIdentify training needs for video detection tools\nEvaluate team competence for new project types\nManagement & Documentation (Clause 5, 6, 7.5) — PARTICIPANT\nMaintain video operations documentation\nReport video team KPIs and metrics\nParticipate in Management Review Meetings\nR&D & Design (Clause 8.3) — SUPPORT\nTest new video detection tools and methodologies\nProvide feedback on tool effectiveness\nQualifications & Requirements\nBachelor’s degree; 3+ years managing production teams; Experience in video/media operations; Strong organizational skills\nKey Performance Indicators (KPIs)\nVideo Team Productivity: ≥90%\nDetection Accuracy: ≥95%\nOn-time Delivery: ≥95%\nTraining Completion: 100%\nTeam Utilization: ≥85%\nEmployee Name: Youssef Hamada\nEmployee Signature: _______________________\nDate: _______________________"}'::jsonb WHERE serial = 'F/44-004';
UPDATE public.records SET form_data = '{"serial":"F/44-005","position":"Sports Department Team Leader","reports_to":"Operations Manager (Andrew Maged)","responsibilities":"Operations & Production (Clause 8.1, 8.5) — PRIMARY OWNER\nManage sports-related projects and team assignments\nEnsure sports analytics deliverables meet accuracy and timeliness requirements\nMonitor match/event data coverage completeness\nCoordinate with Tennis Team (Khaled Magdy) on overlapping projects\nReport on sports project status and performance\nQuality & Audit (Clause 9, 10) — SUPPORT\nImplement quality checks for sports data accuracy\nEnsure sports analytics meet client specifications\nReport and correct nonconforming outputs\nHR & Training (Clause 7.2, 7.3) — SUPPORT\nTrain team members on sport-specific analytics requirements\nEnsure team competence in sport knowledge and tools\nManagement & Documentation (Clause 5, 6, 7.5) — PARTICIPANT\nMaintain sports project documentation\nReport KPIs to Operations Manager\nQualifications & Requirements\nBachelor’s degree; Knowledge of sports analytics; Data analysis skills; Team management experience\nKey Performance Indicators (KPIs)\nSports Data Accuracy: ≥95%\nEvent Coverage: 100%\nOn-time Reporting: ≥95%\nEmployee Name: Maria Maged\nEmployee Signature: _______________________\nDate: _______________________"}'::jsonb WHERE serial = 'F/44-005';
UPDATE public.records SET form_data = '{"serial":"F/44-006","position":"QMS Team Leader","reports_to":"CEO (Kareem Yehia)","responsibilities":"Management & Documentation (Clause 5, 6, 7.5) — PRIMARY OWNER\nMaintain the Quality Manual (M/01) and ensure it reflects current operations\nControl all QMS documentation: procedures (P/##), forms (F/##), records\nMaintain Master Document List and Distribution List\nManage Document Change Notes and revision control\nPrepare agendas and minutes for Management Review Meetings\nTrack action items from Management Reviews to completion\nMaintain the QMS platform and ensure data integrity\nReport QMS performance to CEO\nQuality & Audit (Clause 9, 10) — PRIMARY OWNER\nPlan and coordinate internal audits (annual audit program)\nTrain and manage internal auditors\nTrack NCRs and CARs to closure\nReview corrective action effectiveness\nMaintain the Risk Register and Risk Opportunity Analysis\nMonitor quality objectives and KPIs across all departments\nCoordinate with Operations Managers on quality improvements\nHR & Training (Clause 7.2, 7.3) — SECONDARY OWNER\nMaintain Competence Matrix for all employees\nConduct gap analysis between required and actual competence\nCoordinate with HR (T360) on training programs\nEnsure all employees are aware of Quality Policy and QMS requirements\nMaintain training records and competence evidence\nSales & Customer Service (Clause 8.2, 9.1.2) — SUPPORT\nMonitor customer satisfaction surveys and feedback\nTrack customer complaints and ensure resolution\nCalculate and report Customer Satisfaction Index\nProcurement & Vendors (Clause 8.4) — SUPPORT\nMaintain Approved Supplier List and evaluation records\nAssess supplier conformity to quality requirements\nOperations & Production (Clause 8.1, 8.5) — SUPPORT\nVerify service conformity through quality monitoring\nMaintain Process Interaction Map\nMonitor operational KPIs through QMS Dashboard\nR&D & Design (Clause 8.3) — SUPPORT\nEvaluate new project types for QMS compliance\nDocument feasibility testing outcomes\nLegal Compliance — PRIMARY OWNER\nMaintain Legal Register of applicable regulations\nMonitor compliance with data protection laws (GDPR, local)\nEnsure legal requirements are communicated to relevant staff\nQualifications & Requirements\nBachelor’s degree; ISO 9001:2015 Lead Auditor training; 3+ years QMS experience; Strong documentation and analytical skills; Knowledge of BPO operations\nKey Performance Indicators (KPIs)\nQMS Compliance: 100%\nAudit Completion: 100% on schedule\nCAR Closure: Within 30 days\nDocument Currency: All docs updated within review period\nManagement Review: Every 6 months\nEmployee Name: Ahmed Khaled\nEmployee Signature: _______________________\nDate: _______________________"}'::jsonb WHERE serial = 'F/44-006';
UPDATE public.records SET form_data = '{"serial":"F/44-007","position":"Data Quality Specialist","reports_to":"Operations Manager / QA Leader (Andrew Maged)","responsibilities":"Quality & Audit (Clause 9, 10) — PRIMARY OWNER\nPerform quality checks on data annotation and labeling outputs\nVerify accuracy rates against benchmark datasets\nMonitor quality measurement tools and ensure calibration\nDocument quality check results and maintain records\nFlag nonconforming outputs and initiate corrections\nReport quality metrics to QA Leader (Andrew Maged)\nOperations & Production (Clause 8.1, 8.5) — SUPPORT\nSupport operational teams with quality standards clarification\nPerform random sampling checks during service delivery\nVerify data accuracy at each project stage\nManagement & Documentation (Clause 5, 6, 7.5) — PARTICIPANT\nMaintain quality check records and documentation\nReport quality KPIs for QMS Dashboard\nQualifications & Requirements\nBachelor’s degree in relevant field; Strong attention to detail; Experience with data annotation tools; Analytical skills; Quality control experience\nKey Performance Indicators (KPIs)\nAnnotation Accuracy: ≥95%\nQuality Check Coverage: ≥10% sampling\nIssue Detection Rate: ≥90%\nTool Calibration: Monthly verification\nEmployee Name: Mario Ehab\nEmployee Signature: _______________________\nDate: _______________________"}'::jsonb WHERE serial = 'F/44-007';
