UPDATE public.records SET form_data = '{"audit_type":"Internal Quality Audit","date_of_audit":"26/01/2026","serial":"F/48-001","audit_team":"Internal Audit Team","audit_standard":"ISO 9001:2015","audit_location":"VEZLOO – Operations (Remote)","audit_scope":"Company-wide QMS (Operations, Production, Quality, Training & Support)","auditee":"Operations & Quality Teams","summary_report":"The internal audit was conducted to evaluate the implementation and effectiveness of the Quality Management System in accordance with ISO 9001:2015 requirements.\nThe audit confirmed that core operational processes are implemented and functioning effectively. No major nonconformities were identified. Several observations were noted related to documentation standardization and formalization.","audit_findings":"No Major or Minor Nonconformities identified.\n\nObservations raised for improvement in documentation control, quality objectives documentation, and CAPA formalization.","followup_required":"Yes","auditor_signature":"Ahmed Khaled"}'::jsonb WHERE serial = 'F/48-001';
